INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (559, 161052, 9, 678, '咖啡3：1厦大留学生队（点评）', '炎热的下午，踢一场球赛是一种“享受“好象很多人都不愿意享受啊~~2点10分，对方早以到齐（难道他们不知道迟到是咖啡的一贯作风吗），我们的人才断断续续到来~~~风中的孩子和亨得力，农民最早到，在此表扬一下，双子队长最后到，批评一下。  ⌒ō⌒  ，天啊，原来是群老外，不知道是不是货真假时，看他们玩球都玩的挺刁的~~此时不知道谁说了一句”今天有种不祥的预感”因为昨天国米也输了，哦，对不起好像是我~废话少说，进入比赛。刚开场咖啡的功势很猛，但得誓不得分，苯头鱼和阿宾浪费了几次良机，但造成了一定威胁，过了10分种，那群老外突然缓过劲来，在那个酷似巴哈的8号的带领下疯狂反扑，咖啡一度曾招架不住，但还好，风中的孩子跟双子多次化险为夷，才保住球门，中段，FOOTBALLBOY抓住一次机会，在禁区右侧一脚漂亮的抽射打开了胜力之门，随后，在FOOTBALLBOY跟农民的积极拼抢下对方找不到任合机会，而我们又在左边路又打出了几次漂亮的突破，可每到传中时却总是……下半场，农民去当门将，苏克，潘采夫，穿牛仔裤的POB，KINO先后上阵，可开场不久就被对方攻入一球，1：1，老外门似乎看到嬴球的希望，但随着盘菜腐的再次破门就化成了泡影，这里球是本人在中线一脚直传，潘采夫突破后打入的，非常精彩，随后，锋疯在中场突破一直带球向前冲，他想干什么？？原来他表演了一次非常精彩的假摔（荣获本年度奥斯卡足球奖），惨叫了一声就倒下了……当然我们的裁判也很帮忙，任意球被门将扑出。这时咖啡的后防频频告急，但凭借风中的孩子神勇的表现，（不愧是北方大汉！）撑了过来，农民伯伯的一次酷似巴特斯的表演差点把锋疯的奥斯卡奖抢走。突然，双子队长在后场一脚精准的长传交给穿牛仔裤的POB，POB停了一下，突然从后卫中突围，冲入禁区，一脚冷静的推射中的。怎么可能？？他穿牛仔裤还跑的这么快？？难道鬼上身？后来，苏克先生好象受伤下场，但在全体队员的努力下，咖啡保住了胜果。     在次感谢所有到场的人，包括拉拉队，队员，还有几个叫不出来的人……        至于裁判&#183;&#183;我就不多说什么了，大家也清楚。哈哈哈', '炎热的下午，踢一场球赛是一种“享受“好象很多人都不愿意享受啊~~2点10分，对方早以到齐（难道他们不知道迟到是咖啡的一贯作风吗），我们的人才断断续续到来~~~风中的孩子和亨得力，农民最早到，在此表扬一下，双子队长最后到，批评一下。  ⌒ō⌒  ，天啊，原来是群老外，不知道是不是货真假时，看他们玩球都玩的挺刁的~~此时不知道谁说了一句”今天有种不祥的预感”因为昨天国米也输了，哦，对不起好像是我~废话少说，进入比赛。刚开场咖啡的功势很猛，但得誓不得分，苯头鱼和阿宾浪费了几次良机，但造成了一定威胁，过了10分种，那群老外突然缓过劲来，在那个酷似巴哈的8号的带领下疯狂反扑，咖啡一度曾招架不住，但还好，风中的孩子跟双子多次化险为夷，才保住球门，中段，FOOTBALLBOY抓住一次机会，在禁区右侧一脚漂亮的抽射打开了胜力之门，随后，在FOOTBALLBOY跟农民的积极拼抢下对方找不到任合机会，而我们又在左边路又打出了几次漂亮的突破，可每到传中时却总是……下半场，农民去当门将，苏克，潘采夫，穿牛仔裤的POB，KINO先后上阵，可开场不久就被对方攻入一球，1：1，老外门似乎看到嬴球的希望，但随着盘菜腐的再次破门就化成了泡影，这里球是本人在中线一脚直传，潘采夫突破后打入的，非常精彩，随后，锋疯在中场突破一直带球向前冲，他想干什么？？原来他表演了一次非常精彩的假摔（荣获本年度奥斯卡足球奖），惨叫了一声就倒下了……当然我们的裁判也很帮忙，任意球被门将扑出。这时咖啡的后防频频告急，但凭借风中的孩子神勇的表现，（不愧是北方大汉！）撑了过来，农民伯伯的一次酷似巴特斯的表演差点把锋疯的奥斯卡奖抢走。突然，双子队长在后场一脚精准的长传交给穿牛仔裤的POB，POB停了一下，突然从后卫中突围，冲入禁区，一脚冷静的推射中的。怎么可能？？他穿牛仔裤还跑的这么快？？难道鬼上身？后来，苏克先生好象受伤下场，但在全体队员的努力下，咖啡保住了胜果。     在次感谢所有到场的人，包括拉拉队，队员，还有几个叫不出来的人……        至于裁判··我就不多说什么了，大家也清楚。哈哈哈', '我就是锋疯拉~！英俊的疯子喔··哈哈', '2002-05-07 16:12:00', 17, '20020621103345_bbsid_161052_board_9_2d92362c4e.html', '20020621103345');
